pub const UNKNOWN_CATEGORY: &str = "other";

/// Mirrors `categories.py::GENERIC_UTILITY_KEYWORDS` exactly, including the
/// non-obvious fact that a match maps to `"system"`, not `UNKNOWN_CATEGORY`.
const GENERIC_UTILITY_KEYWORDS: &[&str] = &[
    "vpn",
    "update",
    "launcher",
    "helper",
    "installer",
    "setup",
    "service",
];

const CATEGORY_LABELS: &[(&str, &str)] = &[
    ("ide", "IDE"),
    ("browser", "Браузер"),
    ("terminal", "Терминал"),
    ("communication", "Коммуникации"),
    ("office", "Офис"),
    ("task_tracker", "Трекер задач"),
    ("crm", "CRM"),
    ("system", "Система"),
    ("media", "Медиа"),
    ("games", "Игры"),
    ("other", "Другое"),
];

pub fn category_label(category: &str) -> String {
    CATEGORY_LABELS
        .iter()
        .find(|(key, _)| *key == category)
        .map(|(_, label)| label.to_string())
        .unwrap_or_else(|| category.to_string())
}

/// Returns the category for `process_name`, never inspecting window title
/// text. Mirrors `categorize()`'s exact precedence: explicit `overrides`
/// first, then the built-in map, then the generic-utility-keyword
/// heuristic (→ `"system"`), then `UNKNOWN_CATEGORY` as the final fallback.
pub fn categorize(
    process_name: Option<&str>,
    overrides: Option<&BTreeMap<String, String>>,
) -> String {
    let Some(process_name) = process_name else {
        return UNKNOWN_CATEGORY.to_string();
    };
    let name = process_name.trim().to_lowercase();
    if name.is_empty() {
        return UNKNOWN_CATEGORY.to_string();
    }

    if let Some(overrides) = overrides {
        if let Some(category) = overrides.get(&name) {
            return category.clone();
        }
    }

    if let Some((_, category)) = DEFAULT_CATEGORY_MAP.iter().find(|(key, _)| *key == name) {
        return category.to_string();
    }

    if GENERIC_UTILITY_KEYWORDS
        .iter()
        .any(|keyword| name.contains(keyword))
    {
        return "system".to_string();
    }

    UNKNOWN_CATEGORY.to_string()
}

/// Mirrors `processes_for_category()` — used by a future collector to know
/// "is this process already a browser?" before local title classification,
/// not related to window content.
pub fn processes_for_category(
    category: &str,
    overrides: Option<&BTreeMap<String, String>>,
) -> BTreeSet<String> {
    let mut result: BTreeSet<String> = DEFAULT_CATEGORY_MAP
        .iter()
        .filter(|(_, cat)| *cat == category)
        .map(|(name, _)| name.to_string())
        .collect();
    if let Some(overrides) = overrides {
        result.extend(
            overrides
                .iter()
                .filter(|(_, cat)| cat.as_str() == category)
                .map(|(name, _)| name.clone()),
        );
    }
    result
}
